actions.action:
def actors = allActorService.findAll()
actors.each { actor ->
	if (actor.stringId == useCase.stringId) {
		return
	}
	actor = userService.removeGroup(actor, useCase.stringId)
	if (actor.case.processIdentifier != com.netgrif.application.engine.authorization.domain.constants.GroupConstants.PROCESS_IDENTIFIER) {
		return
	}
	def typedActor = (com.netgrif.application.engine.authorization.domain.Group) actor
	if (typedActor.parentGroupId != useCase.stringId) {
		return
	}
	groupService.update(actor, com.netgrif.application.engine.authorization.domain.params.GroupParams.with()
			.parentGroupId(com.netgrif.application.engine.petrinet.domain.dataset.CaseField.withValue([]))
			.build())
}

if (groupIds.value == null) {
	return
}
if (groupIds.rawValue.contains(useCase.stringId)) {
	throw new IllegalArgumentException("Cannot add self as member of the group.")
}

if (parentGroupId.value == null) {
	return
}
if (parentGroupId.rawValue.size() > 1) {
	throw new IllegalArgumentException("Cannot have multiple references to parent group")
}
if (parentGroupId.rawValue[0] == useCase.stringId) {
	throw new IllegalArgumentException("Cannot use self reference as parent group")
}
